package com.agent.runtime.api.impl;  import com.agent.runtime.api.ModelGatewayClient; import org.slf4j.Logger; import org.slf4j.LoggerFactory; import org.springframework.stereotype.Component;  /**  * 模型网关客户端默认实现 (F6 think phase).  *  * <p>骨架阶段简单实现: 返回包含 prompt 摘要的 mock 响应,  * 真实实现应路由到 agent-model-gateway 模块 (OpenAI / Claude / 通义 等).</p>  */ @Component public class ModelGatewayClientImpl implements ModelGatewayClient {      private static final Logger log = LoggerFactory.getLogger(ModelGatewayClientImpl.class);      /** prompt 摘要最大长度, 防止日志过长 */     private static final int PROMPT_SUMMARY_MAX_LEN = 64;      @Override     public String chat(String prompt) {         String summary = summarizePrompt(prompt);         log.info("调用模型网关: promptSummary={}", summary);         String output = "{\"type\":\"thought\",\"prompt\":\"" + summary + "\",\"output\":\"mock-model-output\"}";         log.debug("模型网关返回: {}", output);         return output;     }      /**      * 提取 prompt 摘要用于日志和 mock 响应.      *      * @param prompt 原始 prompt      * @return 截断后的摘要      */     private String summarizePrompt(String prompt) {         if (prompt == null) {             return "null";         }         if (prompt.length() <= PROMPT_SUMMARY_MAX_LEN) {             return prompt;         }         return prompt.substring(0, PROMPT_SUMMARY_MAX_LEN) + "...";     } }